func profileCardClasses(p *model.ChannelProfile, size string, noBanner bool) string {
	classes := []string{"profile-card", "profile-card--" + size, "profile-card--" + p.Platform}
	if noBanner {
		classes = append(classes, "profile-card--no-banner")
	}
	return strings.Join(classes, " ")
}

func profileCardBodyInnerClasses(p *model.ChannelProfile, size string) string {
	classes := []string{"profile-card-body-inner"}
	if size == "hero" {
		classes = append(classes, "profile-card-body-inner--hero")
		if p.Platform == "youtube" || p.Platform == "tiktok" || p.Platform == "instagram" {
			classes = append(classes, "profile-card-body-inner--hero-left")
		} else {
			classes = append(classes, "profile-card-body-inner--hero-center")
		}
	}
	return strings.Join(classes, " ")
}

func profileLabel(p *model.ChannelProfile) string {
	if p.DisplayName != "" {
		return p.DisplayName
	}
	return p.Handle
}

func profileFollowersLabel(props PageProps, platform string) string {
	if platform == "youtube" {
		return L(props, "profile_subscribers", "Subscribers")
	}
	return L(props, "profile_followers", "Followers")
}

