func profileCardHref(p *model.ChannelProfile) string {
	if p == nil || strings.TrimSpace(p.ChannelID) == "" {
		return "#"
	}
	return "/channels/" + p.ChannelID
}

func profileSupportsRepostToggle(platform string) bool {
	switch strings.ToLower(strings.TrimSpace(platform)) {
	case "twitter", "x", "tiktok", "instagram":
		return true
	default:
		return false
	}
}

func profileRepostOffLabel(props PageProps, platform string) string {
	if isXPlatform(platform) {
		return L(props, "feed_turn_off_retweets", "Turn off retweets")
	}
	return L(props, "feed_turn_off_reposts", "Turn off reposts")
}

func profileRepostOnLabel(props PageProps, platform string) string {
	if isXPlatform(platform) {
		return L(props, "feed_turn_on_retweets", "Turn on retweets")
	}
	return L(props, "feed_turn_on_reposts", "Turn on reposts")
}

// verifiedClass maps (platform, verifiedType) to a CSS modifier class.
func verifiedClass(platform, t string) string {
	if platform == "twitter" {
		switch t {
		case "business":
			return "gold"
		case "government":
			return "grey"
		default:
			return "blue"
		}
	}
	return "plain"
}

// formatCount renders numbers like Twitter: 237.9M, 24.8K, 2,203.
func formatCount(n int) string {
	switch {
	case n >= 1_000_000:
		return fmt.Sprintf("%.1fM", float64(n)/1_000_000)
	case n >= 10_000:
		return fmt.Sprintf("%.1fK", float64(n)/1_000)
	case n >= 1_000:
		return addThousandsSep(n)
	default:
		return fmt.Sprintf("%d", n)
	}
}

func addThousandsSep(n int) string {
	s := fmt.Sprintf("%d", n)
	if len(s) <= 3 {
		return s
	}
	var b strings.Builder
	first := len(s) % 3
	if first > 0 {
		b.WriteString(s[:first])
		if len(s) > first {
			b.WriteByte(',')
		}
	}
	for i := first; i < len(s); i += 3 {
		b.WriteString(s[i : i+3])
		if i+3 < len(s) {
			b.WriteByte(',')
		}
	}
	return b.String()
}

